        private bool SetupSimulatedWindGaugeTimerForNewStart()
        {
            if (_WindGaugeTimer == null)
            {
                Debug.WriteLine("WindGauge timer is not initialized.");
                return false;
            }

            int currentCount = GetLoopCount();
            if (currentCount >= (int)LoopCountState.InitialCountValue)
            {
                Debug.WriteLine("Cannot change acquisition parameters while timer is running.");
                MessageBox.Show("Cannot change acquisition parameters while timer is running. Please stop the timer before changing parameters.", "Parameter Change Not Allowed", MessageBoxButton.OK, MessageBoxImage.Warning);
                return false;
            }
            SiriccoWindGaugePeriod = TimeSpan.FromSeconds(1.0 / WindGauge.AcquisitionDurationSecs);
            _WindGaugeTimer.Interval = SiriccoWindGaugePeriod;
            MaxLoops = WindGauge.SiriccoAcquisitionMeasurementsPerSecDefault * WindGauge.AcquisitionDurationSecs;
            return true;
        }

        private bool  SetupSimulatedWindGaugeTimerInitial()
        {
            SetLoopCount((int)LoopCountState.Stopped);
            WindGauge.AcquisitionDurationSecs = (int)LoopCountState.CountPerSecDefault;
            WindGauge.SiriccoWindGaugeCaptureCountsPerSec = (int) LoopCountState.AcquisitionDurationSecsDefault; ;
            return SetupSimulatedWindGaugeTimerForNewStart();
        }

        /// <summary>
        /// Sets up and starts the simulated WindGauge timer with default parameters. 
        /// The timer will send speed data at the configured rate.
        /// It will automatically stop counting when max value is reached and signal thus
        ///    ... but will not stop sending data until the timer is stopped.
        /// If the timer is already running, it will not be restarted and a warning will be shown. 
        /// If an attempt to change the acquisition parameters while the timer is counting, they are ignored.
        /// </summary>
        public void WindGaugeStart()
        {     
            if (_WindGaugeTimer == null)
            {
                Debug.WriteLine("WindGauge timer is not initialized.");
                return;
            }
            if (_WindGaugeTimer.IsEnabled)
            {
                Debug.WriteLine("WindGauge timer is already running. Restart is not allowed.");
                MessageBox.Show("WindGauge timer is already running. Please stop the timer before restarting.", "Restart Not Allowed", MessageBoxButton.OK, MessageBoxImage.Warning);
                return;
            }
            if (!SetupSimulatedWindGaugeTimerForNewStart())
            {
                Debug.WriteLine("Failed to set up WindGauge timer for initial start.");
                return;
            }
            SetLoopCount((int)LoopCountState.SignalStartSending);
            _WindGaugeTimer.Start();    
        }

        /// <summary>
        /// This signals the simulated WindGauge timer to stop.
        /// </summary>
        public void WindGaugeStop()
        {
            SetLoopCount((int)LoopCountState.SignalStopTimer);
            _WindGaugeTimer.Stop();
        }


        private int GetLoopCount()
        {
            lock (_loopCountLock)
            {
                return _loopCount;
            }
        }

        private void SetLoopCount(int value)
        {
            lock (_loopCountLock)
            {
                _loopCount = value;
            }
        }

        private int GetLoopCount2()
        {
            lock (_loopCountLock2)
            {
                return _loopCount2;
            }
        }

        private void ClearLoopCount2()
        {
            lock (_loopCountLock2)
            {
                _loopCount2 = 0;
            }
        }
        private void SetLoopCount2(int value)
        {
            lock (_loopCountLock2)
            {
                _loopCount2 = value;
            }
        }

        private int IncrementLoopCount2()
        {
            lock (_loopCountLock2)
            {
                return ++_loopCount2;
            }
        }

