        public SiriccoWindow(MainViewModel vm, MainWindow mainWindow = null)
        {
            _vm = vm;
            _mainWindow = mainWindow;
            _vm.WindGaugeStart = WindGaugeStart;
            _vm.WindGaugeStop = WindGaugeStop;
            InitializeComponent();
            DataContext = _vm;
            if(!string.IsNullOrEmpty(_vm?.SelectedReceivePortName))
                _vm.ConnectReceive(_vm.SelectedReceivePortName);

            _vm.PropertyChanged += VmOnPropertyChanged;
            _vm.SiriccoDataReceived += VmOnSiriccoDataReceived;

            Loaded += (_, _) => ApplyAnchorLayout();
            SizeChanged += (_, _) => ApplyAnchorLayout();

            _WindGaugeTimer = new DispatcherTimer
            {
                Interval = SiriccoWindGaugePeriod
            };
            SetupSimulatedWindGaugeTimerInitial();
            _WindGaugeTimer.Tick += async (_, _) =>
            {
                byte[] cmdbytes = new byte[0];
                double WindSpeed = new Random().Next(-100, 100); // Simulate wind speed measurement
                WindSpeed /= 10.0;
                int uVector = 0;
                if (WindSpeed < 0)
                    uVector = 1;
                string msg = $" Q,{WindSpeed:+0.0},{uVector},00,M,";
                byte cs = 0;
                foreach (char c in msg)
                {
                    cs ^= (byte)c;
                }
                var msgBytes = msg.Select(c => (byte)c).ToArray();
                cmdbytes = new byte[msgBytes.Length + 5];
                cmdbytes[0] = (byte)CharCommand.STX;
                Array.Copy(msgBytes, 0, cmdbytes, 1, msgBytes.Length);
                cmdbytes[msgBytes.Length + 1] = (byte)CharCommand.ETX;
                cmdbytes[msgBytes.Length + 2] = cs;
                cmdbytes[msgBytes.Length + 3] = (byte)CharCommand.CR;
                cmdbytes[msgBytes.Length + 4] = (byte)CharCommand.LF;
                var payload = cmdbytes;
                await BeginAutoSend(payload);
            };


            //UpdateSiriccoStartButtonContent();
            //UpdateWallClockEnabledState();
            //UpdateNumDigitsEnabledState();
            //UpdateSendEnabledState();
            //UpdateRaceTimerEnabledState();
            //UpdateLapContinueButton();
        }

        private void VmOnPropertyChanged(object? sender, PropertyChangedEventArgs e)
        {
