            base.OnClosed(e);
        }

        private async void Siricco_StartButton(object sender, RoutedEventArgs e)
        {
            if (_SiriccoIsRunning)
            {
                _SiriccoIsRunning = false;
                _vm.SiriccoIsRunning = false;
                _vm.IsRaceRunning = false;
                //_raceStopwatch.Stop();

                //_WindGaugeTimer.Stop();

                _sendWallClockWhileRunning = false;


                UpdateTimeInputFromRaceElapsed();
                _vm.Status = "Race timer stopped.";

                UpdateSiriccoStartButtonContent();
                UpdateWallClockEnabledState();
                UpdateNumDigitsEnabledState();
                UpdateSendEnabledState();
                UpdateLapContinueButton();

                return;
            }

            if (_SiriccoHasStartedSinceReset)
            {
                //SendCmd(TcpCommand.WindGauge_Reset_Stop_Clear);
                speedTally = 0.0;
                _raceStopwatch.Reset();
                _raceElapsed = TimeSpan.Zero;
                _sendWallClockWhileRunning = false;
                _SiriccoHasStartedSinceReset = false;
                _vm.RaceHasStartedSinceReset = false;
                _vm.IsRaceRunning = false;

                // Send clear command to display
                if (_vm.IsConnected)
                {
                    try
                    {
                        var clearCommand = TcpCommandDefinitions.GetPayloadBytes(TcpCommand.Roller_Time_Mode_Clear).ToArray();
                        await _vm.SendRawAsync(clearCommand);
                        _vm.Status = $"Sent {clearCommand.Length} byte(s) to {_vm.ConnectedPortName}.";
                    }
                    catch (Exception ex)
                    {
                        _vm.Status = ex.Message;
                    }
                }

                _vm.TimeInput = string.Empty;
                UpdateTimeInputFromRaceElapsed();
                _vm.Status = "Race timer reset.";

                UpdateSiriccoStartButtonContent();
                UpdateWallClockEnabledState();
                UpdateNumDigitsEnabledState();
                UpdateSendEnabledState();
                UpdateLapContinueButton();

                return;
            }

            _SiriccoIsRunning = true;
            _vm.SiriccoIsRunning = true;
            _vm.IsRaceRunning = true;

            ClearLoopCount2();
            //SetLoopCount((int)LoopCountState.InitialCountValue);

            speedTally = 0.0;
            //SendCmd(TcpCommand.WindGauge_Start_of_Measurement);
            _WindGaugeTimer.Start();

            _sendWallClockWhileRunning = _vm.UseWallClockTimeOfDay;
            _SiriccoHasStartedSinceReset = true;
            _vm.RaceHasStartedSinceReset = true;




            UpdateTimeInputFromRaceElapsed();
            _vm.Status = "Race timer started.";

            UpdateSiriccoStartButtonContent();
            UpdateWallClockEnabledState();
            UpdateNumDigitsEnabledState();
            UpdateSendEnabledState();
            UpdateLapContinueButton();
        }


