            }

            var enabled = _vm.IsConnected;
            btnSiriccoStart.IsEnabled = enabled;

            if (!enabled && (_SiriccoIsRunning || _SiriccoHasStartedSinceReset))
            {
                ResetRaceTimerState();
            }
        }

        private async void ResetRaceTimerState()
        {
            _SiriccoIsRunning = false;
            _vm.SiriccoIsRunning = false;
            _vm.IsRaceRunning = false;
            _raceStopwatch.Reset();
            _raceElapsed = TimeSpan.Zero;
            _sendWallClockWhileRunning = false;
            _SiriccoHasStartedSinceReset = false;
            _vm.RaceHasStartedSinceReset = false;

            // Send clear command to display
            if (_vm.IsConnected)
            {
                try
                {
                    var clearCommand = TcpCommandDefinitions.GetPayloadBytes(TcpCommand.Roller_Time_Mode_Clear).ToArray();
                    await _vm.SendRawAsync(clearCommand);
                    _vm.Status = $"Sent {clearCommand.Length} byte(s) to {_vm.ConnectedPortName}.";
                }
                catch (Exception ex)
                {
                    _vm.Status = ex.Message;
                }
            }

            _vm.TimeInput = string.Empty;
            UpdateTimeInputFromRaceElapsed();

            UpdateSiriccoStartButtonContent();
            UpdateWallClockEnabledState();
            UpdateNumDigitsEnabledState();
            UpdateSendEnabledState();
            UpdateLapContinueButton();
        }

        private async Task BeginAutoSend(byte[] cmdbytes)
        {
            if (_autoSendInProgress || _isClosing)
            {
                return;
            }

            _autoSendInProgress = true;
            try
            {
                if (!_isClosing)
                {
                    await _vm.SendRawAsync(cmdbytes);
                    //_vm.SendStatus = $"Sent {cmdbytes.Length} byte(s) {cmdbytes} to {portName}.";
                    string csv = string.Join("_", cmdbytes.Select(b => MainViewModel.CharCommandToString((CharCommand)b)));
                    csv = csv.Replace(" ", "<SPC>");
                    csv = csv.Replace("_", "");

                    _vm.SendStatus = $"Sent:\t{csv}";
                }
            }
            catch (Exception ex)
            {
                if (!_isClosing)
                {
                    _vm.Status = ex.Message;
                }
            }
            finally
            {
                _autoSendInProgress = false;
            }
        }

        private void UpdateTimeInputFromRaceElapsed()
        {
            var hours = (int)_raceElapsed.TotalHours;
            var minutes = _raceElapsed.Minutes;
            var seconds = _raceElapsed.Seconds;
            var tenths = _raceElapsed.Milliseconds / 100;
            var hundredths = (_raceElapsed.Milliseconds / 10) % 100;

            if (hours > 0)
            {
                if (hours > 9)
                {
                    hours = 9;
                }

                _vm.TimeInput = $"{hours}:{minutes:00}:{seconds:00}.{tenths}";
                return;
            }

            var totalMinutes = (int)_raceElapsed.TotalMinutes;
            if (totalMinutes > 99)
            {
                totalMinutes = 99;
            }

            _vm.TimeInput = $"{totalMinutes:00}:{seconds:00}.{hundredths:00}";
        }

        private byte[] BuildExpandedPayload(string cmd)
        {
            var xx =  cmd.Select(c => (byte)c).ToArray();
            var x2 = new byte[cmd.Length];
            int i = 0;
            foreach (char c in cmd)
            {
                byte b = (byte)c;
                x2[i++] = b;
                
            }

            return xx;
        }

