            // - Send the WindGauge_ReadFrequency TCP command
            // - Configure the serial port for frequency reading mode
            // - Update UI to indicate frequency reading mode is active
        }

        private async void SendClearButton_Click(object sender, RoutedEventArgs e)
        {
            if( _SiriccoIsRunning)
            {
                SendCmd(TcpCommand.WindGauge_Reset_Stop_Clear);

                _SiriccoIsRunning = false;
                _vm.SiriccoIsRunning = false;
                _vm.IsRaceRunning = false;
                _SiriccoHasStartedSinceReset = false;
                _vm.RaceHasStartedSinceReset = false;
                
                UpdateSiriccoStartButtonContent();
                UpdateWallClockEnabledState();
                UpdateNumDigitsEnabledState();
                UpdateSendEnabledState();
                UpdateLapContinueButton();
            }

        }

        private void BackToMainButton_Click(object sender, RoutedEventArgs e)
        {
            // Set current window and save state
            _vm.CurrentWindow = MainViewModel.ActiveWindow.Display;
            _vm.ShowWindGaugeWindow = false;

            if (_mainWindow != null)
            {
                _mainWindow.Show();
            }
            else
            {
                _mainWindow = new MainWindow(_vm);
                _mainWindow.Show();
            }
            this.Hide();
        }

        private void ExitButton_Click(object sender, RoutedEventArgs e)
        {
            _vm.BeginShutdown();
            Application.Current.Shutdown();
        }

        private void Window_Closing(object sender, System.ComponentModel.CancelEventArgs e)
        {
            _vm.BeginShutdown();
            Application.Current.Shutdown();
        }
    }
}
